// reactapp/src/App.js
import React, { useState } from "react";
import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import LoginRegister from "./components/LoginRegister";
import AppointmentForm from "./components/AppointmentForm";
import AppointmentList from "./components/AppointmentList";
import DoctorDashboard from "./components/DoctorDashboard";

function RequireAuth({ children }) {
  const user = localStorage.getItem("user");
  if (!user) return <Navigate to="/login" replace />;
  return children;
}

function MainApp() {
  const [mode, setMode] = useState("book"); // "book" or "view"

  return (
    <div style={{ maxWidth: 900, margin: "20px auto", padding: 12 }}>
      <header style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
        <h1 style={{ margin: 0 }}>Clinic App</h1>
        <div>
          <button
            onClick={() => { localStorage.removeItem("user"); window.location.href = "/login"; }}
            style={{ marginLeft: 12 }}
          >
            Logout
          </button>
        </div>
      </header>

      <nav style={{ marginBottom: 18, display: "flex", gap: 8 }}>
        <button onClick={() => setMode("book")} style={{ padding: "8px 12px", background: mode === "book" ? "#0b74de" : "#f0f0f0", color: mode === "book" ? "#fff" : "#000", border: "none", borderRadius: 6, cursor: "pointer" }}>Book Appointment</button>
        <button onClick={() => setMode("view")} style={{ padding: "8px 12px", background: mode === "view" ? "#0b74de" : "#f0f0f0", color: mode === "view" ? "#fff" : "#000", border: "none", borderRadius: 6, cursor: "pointer" }}>View Appointments</button>
      </nav>

      <main>
        {mode === "book" ? <AppointmentForm /> : <AppointmentList />}
      </main>
    </div>
  );
}

export default function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/login" element={<LoginRegister />} />
        <Route path="/doctor" element={
          <RequireAuth>
            <DoctorDashboard />
          </RequireAuth>
        } />
        <Route path="/" element={
          <RequireAuth>
            <MainApp />
          </RequireAuth>
        } />
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </BrowserRouter>
  );
}
